  ('aboriginal-8b44517b-moex-00059', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '關於條約之敘述，下列何者正確？ 條約乃國際間之協議，故非屬行政法之法源  條約無須送立法院審議 條約不具有法律之效力  條約內容原則上不得違反我國現行法律', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00060', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '依據司法院大法官解釋，立法上運用不確定法律概念者，苟其意義非難以理解，且為受規範者所得預 見，並可經由司法審查加以確認，即不得謂與下列何種原則相違？ 合義務裁量原則  比例原則  信賴保護原則  法律明確性原則', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('aboriginal-8b44517b-moex-00061', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-d1a761c9', 'sub-aboriginal-8b44517b-04', NULL, 'single_choice', '下列何者非屬不當聯結禁止原則之內涵？ 行政處分之附款應與該處分之目的具有正當合理之關聯 雙務行政契約中，人民之給付與行政機關之給付應相當，並具有正當合理之關聯 行政機關為裁量時，不得考量無合理關聯之因素 行政機關對相對人為行政指導時，應明示行政指導之目的、內容及負責指導者等事項', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL)
